# Shapes module - classes with inheritance and interface implementation
from types import Color, Point, IDrawable, IMeasurable

# Abstract base class for all shapes
@abstract
class Shape:
    name: str
    color: Color

    def __init__(self, name: str, color: Color):
        self.name = name
        self.color = color

    @abstract
    def area(self) -> float:
        pass

    @virtual
    def describe(self) -> str:
        return f"{self.name} ({self.color.name})"

# Rectangle class - inherits from Shape, implements interfaces
class Rectangle(Shape, IDrawable, IMeasurable):
    width: float
    height: float
    position: Point

    def __init__(self, name: str, width: float, height: float, color: Color):
        super().__init__(name, color)
        self.width = width
        self.height = height
        self.position = Point(0.0, 0.0)

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def draw(self) -> str:
        return f"Drawing rectangle {self.name}"

    @override
    def describe(self) -> str:
        return f"Rectangle {self.name}: {self.width} x {self.height}"

# Circle class - inherits from Shape, implements interfaces
class Circle(Shape, IDrawable, IMeasurable):
    radius: float
    center: Point

    def __init__(self, name: str, radius: float, color: Color):
        super().__init__(name, color)
        self.radius = radius
        self.center = Point(0.0, 0.0)

    @override
    def area(self) -> float:
        # pi * r^2 using approximate pi
        pi: float = 3.14159265359
        return pi * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        # 2 * pi * r
        pi: float = 3.14159265359
        return 2.0 * pi * self.radius

    def draw(self) -> str:
        return f"Drawing circle {self.name}"

    @override
    def describe(self) -> str:
        return f"Circle {self.name}: r={self.radius}"
